import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../utils/api';
import { useAuth } from '../context/AuthContext';
const SAMPLE_PRODUCTS = [
  // Electronics
  { name: 'iPhone 15 Pro', description: 'Latest Apple smartphone with A17 chip and titanium design', price: 999, category: 'Electronics', image: 'https://images.unsplash.com/photo-1695048133142-1a20484d2569?w=400', stock: 30 },
  { name: 'Samsung Galaxy S24', description: 'Flagship Android phone with AI features', price: 799, category: 'Electronics', image: 'https://images.unsplash.com/photo-1610945415295-d9bbf067e59c?w=400', stock: 25 },
  { name: 'MacBook Air M2', description: 'Supercharged by M2 chip, ultra thin design', price: 1199, category: 'Electronics', image: 'https://images.unsplash.com/photo-1517336714731-489689fd1ca8?w=400', stock: 20 },
  { name: 'Sony WH-1000XM5', description: 'Industry leading noise cancelling headphones', price: 349, category: 'Electronics', image: 'https://images.unsplash.com/photo-1505740420928-5e560c06d30e?w=400', stock: 25 },
  { name: 'Samsung 4K TV 55"', description: 'Crystal clear 4K display with smart features', price: 699, category: 'Electronics', image: 'https://images.unsplash.com/photo-1593359677879-a4bb92f829d1?w=400', stock: 15 },
  { name: 'Apple AirPods Pro', description: 'Active noise cancellation wireless earbuds', price: 249, category: 'Electronics', image: 'https://images.unsplash.com/photo-1606220945770-b5b6c2c55bf1?w=400', stock: 40 },
  { name: 'iPad Pro 12.9"', description: 'Most powerful iPad with M2 chip', price: 1099, category: 'Electronics', image: 'https://images.unsplash.com/photo-1544244015-0df4b3ffc6b0?w=400', stock: 18 },
  { name: 'PlayStation 5', description: 'Next generation gaming console', price: 499, category: 'Electronics', image: 'https://images.unsplash.com/photo-1606813907291-d86efa9b94db?w=400', stock: 10 },

  // Shoes
  { name: 'Nike Air Max 270', description: 'Lightweight and comfortable running shoes', price: 129, category: 'Shoes', image: 'https://images.unsplash.com/photo-1542291026-7eec264c27ff?w=400', stock: 50 },
  { name: 'Adidas Ultraboost 23', description: 'Responsive cushioning for runners', price: 189, category: 'Shoes', image: 'https://images.unsplash.com/photo-1608231387042-66d1773070a5?w=400', stock: 40 },
  { name: 'Nike Air Force 1', description: 'Classic basketball shoe turned streetwear icon', price: 109, category: 'Shoes', image: 'https://images.unsplash.com/photo-1600269452121-4f2416e55c28?w=400', stock: 60 },
  { name: 'Converse Chuck Taylor', description: 'All time classic canvas sneaker', price: 69, category: 'Shoes', image: 'https://images.unsplash.com/photo-1607522370275-f6fd21ef34b5?w=400', stock: 70 },
  { name: 'Vans Old Skool', description: 'Classic skate shoe with waffle outsole', price: 79, category: 'Shoes', image: 'https://images.unsplash.com/photo-1525966222134-fcfa99b8ae77?w=400', stock: 55 },
  { name: 'New Balance 574', description: 'Heritage running shoe with modern comfort', price: 89, category: 'Shoes', image: 'https://images.unsplash.com/photo-1539185441755-769473a23570?w=400', stock: 45 },

  // Clothing
  { name: "Levi's 501 Jeans", description: 'Classic straight fit denim jeans', price: 79, category: 'Clothing', image: 'https://images.unsplash.com/photo-1542272604-787c3835535d?w=400', stock: 60 },
  { name: 'Ralph Lauren Polo', description: 'Classic cotton polo shirt', price: 89, category: 'Clothing', image: 'https://images.unsplash.com/photo-1620012253295-c15cc3e65df4?w=400', stock: 45 },
  { name: 'Nike Dri-FIT T-Shirt', description: 'Moisture wicking athletic t-shirt', price: 35, category: 'Clothing', image: 'https://images.unsplash.com/photo-1521572163474-6864f9cf17ab?w=400', stock: 80 },
  { name: 'Winter Puffer Jacket', description: 'Warm insulated jacket for cold weather', price: 149, category: 'Clothing', image: 'https://images.unsplash.com/photo-1547949003-9792a18a2601?w=400', stock: 30 },
  { name: 'H&M Hoodie', description: 'Comfortable cotton blend hoodie', price: 45, category: 'Clothing', image: 'https://images.unsplash.com/photo-1556821840-3a63f15732ce?w=400', stock: 65 },
  { name: 'Formal Blazer', description: 'Slim fit professional blazer', price: 129, category: 'Clothing', image: 'https://images.unsplash.com/photo-1507679799987-c73779587ccf?w=400', stock: 25 },

  // Books
  { name: 'Atomic Habits', description: 'Build good habits and break bad ones by James Clear', price: 18, category: 'Books', image: 'https://images.unsplash.com/photo-1544716278-ca5e3f4abd8c?w=400', stock: 80 },
  { name: 'The Alchemist', description: 'Paulo Coelho inspirational novel', price: 14, category: 'Books', image: 'https://images.unsplash.com/photo-1512820790803-83ca734da794?w=400', stock: 90 },
  { name: 'Rich Dad Poor Dad', description: 'Personal finance classic by Robert Kiyosaki', price: 16, category: 'Books', image: 'https://images.unsplash.com/photo-1554774853-aae0a22c8aa4?w=400', stock: 75 },
  { name: 'Harry Potter Box Set', description: 'Complete 7 book collection by J.K. Rowling', price: 89, category: 'Books', image: 'https://images.unsplash.com/photo-1481627834876-b7833e8f5570?w=400', stock: 40 },
  { name: 'The Great Gatsby', description: 'F. Scott Fitzgerald classic American novel', price: 12, category: 'Books', image: 'https://images.unsplash.com/photo-1543002588-bfa74002ed7e?w=400', stock: 100 },

  // Beauty
  { name: 'Face Serum Vitamin C', description: 'Anti-aging brightening vitamin C serum', price: 45, category: 'Beauty', image: 'https://images.unsplash.com/photo-1570172619644-dfd03ed5d881?w=400', stock: 35 },
  { name: 'Maybelline Lipstick', description: 'Long lasting matte finish lipstick', price: 15, category: 'Beauty', image: 'https://images.unsplash.com/photo-1586495777744-4e6232bf2fd7?w=400', stock: 70 },
  { name: 'Luxury Perfume Set', description: 'Premium fragrance gift set', price: 75, category: 'Beauty', image: 'https://images.unsplash.com/photo-1541643600914-78b084683702?w=400', stock: 40 },
  { name: 'Moisturizer SPF 50', description: 'Daily moisturizer with sun protection', price: 35, category: 'Beauty', image: 'https://images.unsplash.com/photo-1556228578-8c89e6adf883?w=400', stock: 55 },
  { name: 'Eyeshadow Palette', description: '24 color professional eyeshadow palette', price: 29, category: 'Beauty', image: 'https://images.unsplash.com/photo-1512207736890-6ffed8a84e8d?w=400', stock: 60 },

  // Sports ✅ FIXED IMAGES
  { name: 'Yoga Mat Premium', description: 'Non-slip extra thick eco-friendly yoga mat', price: 49, category: 'Sports', image: 'https://images.unsplash.com/photo-1601925228843-69eb89a77c8a?w=400', stock: 30 },
  { name: 'Dumbbell Set 20kg', description: 'Adjustable weight dumbbell set for home gym', price: 89, category: 'Sports', image: 'https://images.unsplash.com/photo-1534438327276-14e5300c3a48?w=400', stock: 20 },
  { name: 'Running Shorts', description: 'Lightweight breathable sports shorts', price: 35, category: 'Sports', image: 'https://images.unsplash.com/photo-1565299507177-b0ac66763828?w=400', stock: 55 },
  { name: 'Football Official Size', description: 'FIFA approved match football', price: 39, category: 'Sports', image: 'https://images.unsplash.com/photo-1579952363873-27f3bade9f55?w=400', stock: 45 },
  { name: 'Resistance Bands Set', description: 'Set of 5 resistance bands for full body workout', price: 25, category: 'Sports', image: 'https://images.unsplash.com/photo-1598289431512-b97b0917afb5?w=400', stock: 60 },
  { name: 'Gym Water Bottle', description: 'Leak proof BPA free sports bottle 1L', price: 19, category: 'Sports', image: 'https://images.unsplash.com/photo-1523362628745-0c100150b504?w=400', stock: 80 },

  // Home
  { name: 'Coffee Maker Pro', description: 'Brew perfect coffee every morning', price: 129, category: 'Home', image: 'https://images.unsplash.com/photo-1495474472287-4d71bcdd2085?w=400', stock: 25 },
  { name: 'Air Fryer XL 5.8L', description: 'Digital air fryer for healthy cooking', price: 99, category: 'Home', image: 'https://images.unsplash.com/photo-1585515320310-259814833e62?w=400', stock: 18 },
  { name: 'Robot Vacuum Cleaner', description: 'Smart robot vacuum with auto mapping', price: 299, category: 'Home', image: 'https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=400', stock: 15 },
  { name: 'Instant Pot 7-in-1', description: 'Multi-use pressure cooker and slow cooker', price: 89, category: 'Home', image: 'https://images.unsplash.com/photo-1556909114-f6e7ad7d3136?w=400', stock: 22 },
  { name: 'Scented Candle Set', description: 'Luxury aromatherapy candle collection', price: 39, category: 'Home', image: 'https://images.unsplash.com/photo-1602028915047-37269d1a73f7?w=400', stock: 50 },
];

const Admin = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [products, setProducts] = useState([]);
  const [orders, setOrders] = useState([]);
  const [tab, setTab] = useState('products');
  const [form, setForm] = useState({ name: '', description: '', price: '', category: '', image: '', stock: '' });
  const [msg, setMsg] = useState('');
  const [loading, setLoading] = useState(false);
  const [seeding, setSeeding] = useState(false);

  useEffect(() => {
    if (!user?.isAdmin) navigate('/');
    fetchProducts();
    fetchOrders();
  }, []);

  const fetchProducts = () => api.get('/products').then(r => setProducts(r.data));
  const fetchOrders = () => api.get('/orders').then(r => setOrders(r.data));

  const handleChange = e => setForm({ ...form, [e.target.name]: e.target.value });

  const handleAddProduct = async e => {
    e.preventDefault();
    setLoading(true);
    try {
      await api.post('/products', { ...form, price: Number(form.price), stock: Number(form.stock) });
      setMsg('✅ Product added!');
      setForm({ name: '', description: '', price: '', category: '', image: '', stock: '' });
      fetchProducts();
    } catch (err) {
      setMsg('❌ ' + (err.response?.data?.message || 'Error'));
    }
    setLoading(false);
  };

  const handleSeedProducts = async () => {
    setSeeding(true);
    setMsg('⏳ Adding sample products...');
    let count = 0;
    for (const p of SAMPLE_PRODUCTS) {
      try {
        await api.post('/products', p);
        count++;
      } catch (e) {}
    }
    setMsg(`✅ Added ${count} sample products!`);
    fetchProducts();
    setSeeding(false);
  };

  const handleDeleteProduct = async id => {
    if (!window.confirm('Delete this product?')) return;
    await api.delete(`/products/${id}`);
    fetchProducts();
  };

  const handleDeleteAll = async () => {
    if (!window.confirm('Delete ALL products? This cannot be undone!')) return;
    for (const p of products) {
      try { await api.delete(`/products/${p._id}`); } catch (e) {}
    }
    fetchProducts();
    setMsg('✅ All products deleted!');
  };

  const handleStatusUpdate = async (id, status) => {
    await api.put(`/orders/${id}/status`, { status });
    fetchOrders();
  };

  const statusColor = s => ({
    pending: '#ff9800', processing: '#2196f3',
    shipped: '#9c27b0', delivered: '#4caf50', cancelled: '#f44336'
  }[s] || '#888');

  return (
    <div style={styles.page}>
      <div style={styles.header}>
        <h2 style={styles.title}>⚙️ Admin Panel</h2>
        <div style={styles.stats}>
          <div style={styles.stat}>
            <span style={styles.statNum}>{products.length}</span>
            <span style={styles.statLabel}>Products</span>
          </div>
          <div style={styles.stat}>
            <span style={styles.statNum}>{orders.length}</span>
            <span style={styles.statLabel}>Orders</span>
          </div>
          <div style={styles.stat}>
            <span style={styles.statNum}>${orders.reduce((s, o) => s + o.totalPrice, 0).toFixed(0)}</span>
            <span style={styles.statLabel}>Revenue</span>
          </div>
        </div>
      </div>

      <div style={styles.tabs}>
        {['products', 'orders', 'add'].map(t => (
          <button key={t} onClick={() => setTab(t)} style={tab === t ? styles.activeTab : styles.tab}>
            {t === 'products' ? '📦 Products' : t === 'orders' ? '📋 Orders' : '➕ Add Product'}
          </button>
        ))}
      </div>

      {/* ADD PRODUCT TAB */}
      {tab === 'add' && (
        <div style={styles.section}>
          <div style={styles.sectionHeader}>
            <h3 style={{ margin: 0 }}>Add New Product</h3>
            <button onClick={handleSeedProducts} disabled={seeding} style={styles.seedBtn}>
              {seeding ? '⏳ Adding...' : '🚀 Add 20 Sample Products'}
            </button>
          </div>
          {msg && <p style={styles.msg}>{msg}</p>}
          <form onSubmit={handleAddProduct} style={styles.form}>
            <div style={styles.formGrid}>
              <input name="name" placeholder="Product Name" value={form.name} onChange={handleChange} style={styles.input} required />
              <input name="price" placeholder="Price (e.g. 99)" value={form.price} onChange={handleChange} style={styles.input} required />
              <input name="category" placeholder="Category (Electronics, Shoes, etc)" value={form.category} onChange={handleChange} style={styles.input} required />
              <input name="stock" placeholder="Stock quantity" value={form.stock} onChange={handleChange} style={styles.input} required />
            </div>
            <input name="image" placeholder="Image URL (https://...)" value={form.image} onChange={handleChange} style={styles.inputFull} />
            <textarea name="description" placeholder="Product description" value={form.description} onChange={handleChange} style={styles.textarea} required />
            <button type="submit" disabled={loading} style={styles.submitBtn}>
              {loading ? 'Adding...' : '➕ Add Product'}
            </button>
          </form>
        </div>
      )}

      {/* PRODUCTS TAB */}
      {tab === 'products' && (
        <div style={styles.section}>
          <div style={styles.sectionHeader}>
            <h3 style={{ margin: 0 }}>All Products ({products.length})</h3>
            <button onClick={handleDeleteAll} style={styles.deleteAllBtn}>🗑 Delete All</button>
          </div>
          {msg && <p style={styles.msg}>{msg}</p>}
          <div style={styles.productTable}>
            {products.map(p => (
              <div key={p._id} style={styles.productRow}>
                <img
                  src={p.image}
                  alt={p.name}
                  style={styles.thumb}
                  onError={e => { e.target.src = 'https://images.unsplash.com/photo-1441986300917-64674bd600d8?w=60'; }}
                />
                <div style={{ flex: 1 }}>
                  <p style={styles.productName}>{p.name}</p>
                  <p style={styles.productCat}>{p.category}</p>
                </div>
                <span style={styles.productPrice}>${p.price}</span>
                <span style={{
                  padding: '4px 10px', borderRadius: '20px', fontSize: '12px',
                  background: p.stock > 10 ? '#e8f5e9' : p.stock > 0 ? '#fff3e0' : '#ffebee',
                  color: p.stock > 10 ? '#2e7d32' : p.stock > 0 ? '#e65100' : '#c62828'
                }}>
                  Stock: {p.stock}
                </span>
                <button onClick={() => handleDeleteProduct(p._id)} style={styles.delBtn}>🗑 Delete</button>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* ORDERS TAB */}
      {tab === 'orders' && (
        <div style={styles.section}>
          <h3>All Orders ({orders.length})</h3>
          {orders.length === 0 && <p style={{ color: '#888' }}>No orders yet.</p>}
          {orders.map(o => (
            <div key={o._id} style={styles.orderRow}>
              <div>
                <p style={styles.orderId}>#{o._id.slice(-8)}</p>
                <p style={styles.orderUser}>{o.user?.name || 'Customer'} — {o.user?.email}</p>
                <p style={styles.orderItems}>{o.items.map(i => `${i.name} ×${i.quantity}`).join(', ')}</p>
              </div>
              <div style={styles.orderRight}>
                <p style={styles.orderTotal}>${o.totalPrice.toFixed(2)}</p>
                <p style={styles.orderDate}>{new Date(o.createdAt).toLocaleDateString()}</p>
                <select
                  value={o.status}
                  onChange={e => handleStatusUpdate(o._id, e.target.value)}
                  style={{ ...styles.statusSelect, borderColor: statusColor(o.status), color: statusColor(o.status) }}
                >
                  {['pending', 'processing', 'shipped', 'delivered', 'cancelled'].map(s => (
                    <option key={s} value={s}>{s.charAt(0).toUpperCase() + s.slice(1)}</option>
                  ))}
                </select>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

const styles = {
  page: { padding: '24px', background: '#f3f3f3', minHeight: '100vh' },
  header: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '24px', flexWrap: 'wrap', gap: '16px' },
  title: { margin: 0, fontSize: '28px' },
  stats: { display: 'flex', gap: '16px' },
  stat: { background: '#fff', padding: '12px 20px', borderRadius: '10px', textAlign: 'center', boxShadow: '0 2px 8px rgba(0,0,0,0.07)' },
  statNum: { display: 'block', fontSize: '24px', fontWeight: 'bold', color: '#e94560' },
  statLabel: { fontSize: '12px', color: '#888' },
  tabs: { display: 'flex', gap: '8px', marginBottom: '20px' },
  tab: { padding: '10px 20px', background: '#fff', border: '1px solid #ddd', borderRadius: '8px', cursor: 'pointer', fontSize: '14px' },
  activeTab: { padding: '10px 20px', background: '#e94560', color: '#fff', border: 'none', borderRadius: '8px', cursor: 'pointer', fontSize: '14px', fontWeight: 'bold' },
  section: { background: '#fff', borderRadius: '12px', padding: '24px', boxShadow: '0 2px 8px rgba(0,0,0,0.07)' },
  sectionHeader: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px', flexWrap: 'wrap', gap: '12px' },
  seedBtn: { padding: '10px 20px', background: '#1a1a2e', color: '#fff', border: 'none', borderRadius: '8px', cursor: 'pointer', fontSize: '14px', fontWeight: 'bold' },
  deleteAllBtn: { padding: '10px 20px', background: '#ffebee', color: '#c62828', border: '1px solid #c62828', borderRadius: '8px', cursor: 'pointer', fontSize: '14px' },
  msg: { padding: '10px 16px', background: '#f0f9f0', borderRadius: '8px', color: '#2e7d32', marginBottom: '16px' },
  form: { display: 'flex', flexDirection: 'column', gap: '12px' },
  formGrid: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '12px' },
  input: { padding: '10px 14px', borderRadius: '8px', border: '1px solid #ddd', fontSize: '14px' },
  inputFull: { padding: '10px 14px', borderRadius: '8px', border: '1px solid #ddd', fontSize: '14px', width: '100%', boxSizing: 'border-box' },
  textarea: { padding: '10px 14px', borderRadius: '8px', border: '1px solid #ddd', fontSize: '14px', minHeight: '80px', resize: 'vertical' },
  submitBtn: { padding: '12px', background: '#e94560', color: '#fff', border: 'none', borderRadius: '8px', cursor: 'pointer', fontSize: '15px', fontWeight: 'bold' },
  productTable: { display: 'flex', flexDirection: 'column', gap: '10px' },
  productRow: { display: 'flex', alignItems: 'center', gap: '16px', padding: '12px', border: '1px solid #f0f0f0', borderRadius: '8px', background: '#fafafa', flexWrap: 'wrap' },
  thumb: { width: '60px', height: '60px', objectFit: 'cover', borderRadius: '8px' },
  productName: { margin: 0, fontWeight: '600', fontSize: '15px' },
  productCat: { margin: 0, color: '#888', fontSize: '12px' },
  productPrice: { fontWeight: 'bold', color: '#e94560', minWidth: '60px' },
  delBtn: { padding: '6px 12px', background: '#ffebee', color: '#c62828', border: 'none', borderRadius: '6px', cursor: 'pointer', fontSize: '13px' },
  orderRow: { display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', padding: '16px', border: '1px solid #f0f0f0', borderRadius: '8px', marginBottom: '10px', background: '#fafafa', flexWrap: 'wrap', gap: '12px' },
  orderId: { margin: '0 0 4px', fontWeight: 'bold', fontFamily: 'monospace' },
  orderUser: { margin: '0 0 4px', color: '#555', fontSize: '13px' },
  orderItems: { margin: 0, color: '#888', fontSize: '12px' },
  orderRight: { textAlign: 'right' },
  orderTotal: { margin: '0 0 4px', fontWeight: 'bold', color: '#e94560', fontSize: '18px' },
  orderDate: { margin: '0 0 8px', color: '#888', fontSize: '12px' },
  statusSelect: { padding: '6px 12px', borderRadius: '6px', border: '2px solid', fontWeight: 'bold', cursor: 'pointer', background: '#fff' },
};

export default Admin;
